spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progress = (t % duration) / duration;

    var centerY = H / 2 - 15;
    var radius = 45;
    var centerX1 = W / 2 - 60;
    var centerX2 = W / 2 + 60;

    var p1 = 0.25; // 0 to 2s: draw shapes
    var p2 = 0.60; // 2s to 4.8s: count and show 7/4
    var p3 = 0.90; // 4.8s to 7.2s: group and show 1 3/4

    // Draw slices
    function drawCake(centerX, startIdx, colorShade, highlight) {
      var totalSlices = 4;
      for (var i = 0; i < totalSlices; i++) {
        var idx = startIdx + i;
        var startAngle = i * (Math.PI * 2 / totalSlices) - Math.PI / 2;
        var endAngle = (i + 1) * (Math.PI * 2 / totalSlices) - Math.PI / 2;

        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        ctx.arc(centerX, centerY, radius, startAngle, endAngle);
        ctx.closePath();

        if (idx < 7) {
          ctx.fillStyle = colorShade;
          ctx.fill();
          ctx.strokeStyle = highlight ? '#60A5FA' : '#4B5563';
        } else {
          ctx.fillStyle = '#1F2937';
          ctx.fill();
          ctx.strokeStyle = '#374151';
        }
        ctx.lineWidth = highlight ? 2.5 : 1.5;
        ctx.stroke();
      }
    }

    // Shading colors
    var color = '#3B82F6'; // Blue
    if (progress >= p2) {
      // Highlight whole cake in green when grouped
      drawCake(centerX1, 0, '#10B981', true);
      drawCake(centerX2, 4, '#3B82F6', false);
    } else {
      drawCake(centerX1, 0, '#3B82F6', false);
      drawCake(centerX2, 4, '#3B82F6', false);
    }

    // Text annotations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 12px -apple-system, sans-serif';

    if (progress < p2) {
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('4/4 slices', centerX1, centerY + radius + 15);
      ctx.fillText('3/4 slices', centerX2, centerY + radius + 15);

      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Representing 7 Quarters', W / 2, H - 35);
    } else if (progress < p3) {
      // Counting view
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('1, 2, 3, 4', centerX1, centerY + radius + 15);
      ctx.fillText('5, 6, 7', centerX2, centerY + radius + 15);

      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Improper Form: 7/4', W / 2, H - 35);
      ctx.fillStyle = '#60A5FA';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('Count 7 individual quarter-slices', W / 2, H - 15);
    } else {
      // Grouped view
      ctx.fillStyle = '#10B981';
      ctx.fillText('1 Whole', centerX1, centerY + radius + 15);
      ctx.fillStyle = '#3B82F6';
      ctx.fillText('3/4 Remaining', centerX2, centerY + radius + 15);

      ctx.fillStyle = '#34D399';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Mixed Number Form: 1 ¾', W / 2, H - 35);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('4/4 grouped into 1 whole + 3/4 left over', W / 2, H - 15);
    }
  }
};
